   * Remove timestamps older than the window start. Because timestamps are
   * pushed in chronological order, all expired entries are at the front, so we
   * find the first still-valid index and slice once.
   */
  function prune(timestamps, windowStart) {
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    return firstValid === 0 ? timestamps : timestamps.slice(firstValid);
