/**
 * sliding-window-rate-limiter.js
 *
 * TRUE sliding-window rate-limiter middleware for Express.js.
 * Each client IP maintains a log of request timestamps; on every
 * incoming request the log is trimmed to the live window before the
 * limit is checked, so the allowed call-rate is evaluated against a
 * continuously moving time range — never against a fixed bucket that
 * resets on a clock boundary.
 *
 * ─── Proxy / req.ip note ──────────────────────────────────────────────────────
 * Express derives req.ip from the X-Forwarded-For header ONLY when the
 * "trust proxy" setting is enabled:
 *
 *   app.set('trust proxy', 1);  // trust first hop  (e.g. Nginx on the same host)
 *   app.set('trust proxy', 2);  // trust two hops   (e.g. CDN → load-balancer)
 *
 * Without it, req.ip is always the raw socket address — every client behind
 * a reverse-proxy looks identical and they all share a single rate-limit bucket.
 *
 * Conversely, if "trust proxy" is enabled on an internet-facing server, a
 * malicious client can forge X-Forwarded-For to impersonate other IPs and
 * bypass per-IP limits. Enable the setting only when a trusted proxy sits
 * in front of Node.
 * ──────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   Sliding-window length in milliseconds.
 * @property {number} [maxRequests=100]  Max requests allowed within the window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware  Express middleware.
 * @property {() => void}                        close      Stops the cleanup timer.
 */

/**
 * Creates a sliding-window rate-limiter middleware for Express.
 *
 * Algorithm (per client IP on every request):
 *   1. Load the timestamp log for this IP (or start an empty log).
 *   2. SLIDE the window — discard every timestamp older than (now − windowMs).
 *      This is the core property of a sliding window: the checked interval
 *      always ends *right now*, not at the next fixed clock tick.
 *   3. Count remaining (in-window) timestamps.
 *      • count >= maxRequests → reject, HTTP 429.
 *      • count <  maxRequests → record `now`, set headers, call next().
 *
 * @param {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default 1 minute
  const maxRequests = options.maxRequests ?? 100;    // default 100 req/window

  // Primary store: Map<ip, number[]>
  // Each array holds in-window request timestamps in ascending order.
  // Timestamps are appended in real time, so order is naturally maintained
  // without explicit sorting.
  const store = new Map();

  // ── Background cleanup ─────────────────────────────────────────────────────
  // Runs every 60 s and evicts entries for IPs that have been idle for longer
  // than windowMs. Without this, the store would grow unboundedly with unique
  // IPs (scanners, one-off clients, bots, etc.).
  //
  // We check the *newest* timestamp in each log: if even that is older than the
  // window, the entire log is stale and can be removed.
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // Prevent the timer from keeping the Node process alive when all other async
  // work is done (critical in test suites and serverless warm-start scenarios).
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // ── Middleware ─────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const now    = Date.now();
    const cutoff = now - windowMs;

    // Prefer req.ip (respects trust-proxy); fall back to the raw socket address.
    const ip = req.ip || (req.socket && req.socket.remoteAddress) || 'unknown';

    // Step 1 — load the existing log (or an empty array for a new IP).
    let timestamps = store.get(ip) ?? [];

    // Step 2 — slide the window.
    // Timestamps are stored in ascending order, so stale entries accumulate at
    // the front. A single left-to-right scan is sufficient to find the cutoff.
    //
    // findIndex returns the index of the first timestamp still inside the window.
    // If ALL timestamps are stale, firstValid === -1 and we start fresh.
    const firstValid = timestamps.findIndex(t => t > cutoff);
    timestamps = firstValid === -1 ? [] : timestamps.slice(firstValid);

    // Step 3a — check the limit BEFORE recording this request so that the
    // window reflects only previously-allowed calls.
    if (timestamps.length >= maxRequests) {
      // The client must wait until the oldest in-window timestamp ages out.
      // timestamps[0] is guaranteed to exist (length >= maxRequests >= 1).
      const retryAfterMs   = timestamps[0] + windowMs - now; // always > 0
      const retryAfterSecs = Math.ceil(retryAfterMs / 1000);

      // Persist the trimmed (but still full) log so the next cleanup pass
      // operates on accurate data.
      store.set(ip, timestamps);

      res.set('Retry-After', String(retryAfterSecs));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSecs,
      });
    }

    // Step 3b — allow: record this request's timestamp.
    timestamps.push(now);
    store.set(ip, timestamps);

    // ── Response headers ───────────────────────────────────────────────────
    //
    // X-RateLimit-Limit     — the configured ceiling.
    // X-RateLimit-Remaining — slots still available in the current window.
    // X-RateLimit-Reset     — epoch second at which the oldest in-window request
    //                         slides out and one new slot opens up.
    //                         (If this is the IP's very first request, timestamps[0]
    //                         === now, so Reset = now + windowMs.)
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpochSec),
    });

    next();
  }

  // ── close() — stop the background timer ───────────────────────────────────
  // Call this during graceful shutdown or in test teardown to let Node exit
  // cleanly without waiting for the interval to fire on its own.
  function close() {
    clearInterval(cleanupTimer);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
